const INSURANCE_TYPES = ["oc","ac","gap","nnw","assistance","cargo"];
const CONTRACT_TYPES  = ["umowa_leasing","umowa_gps","umowa_serwis","umowa_inna"];

// ═══════════════════════════════════════════════════════════════════════════════
// TRIP SUMMARY HELPERS (podsumowanie trasy)
// ═══════════════════════════════════════════════════════════════════════════════
const TRIP_TOLERANCE_MIN = 15; // ≤15 min spóźnienia = "na czas"
const SPALANIE_DEFAULT_NORMA = 30;   // fallback gdy pojazd nie ma ustawionego progu (l/100km)
const SPALANIE_DEFAULT_ALARM = 38;

// Parsuje "YYYY-MM-DD" + "HH:MM" do Date (lokalny czas)
function parsePlannedDateTime(date, time) {
  if (!date) return null;
  try {
    // Gdy brak godziny — przyjmujemy koniec dnia (23:59) jako deadline "soft"
    const t = (time && /^\d{1,2}:\d{2}$/.test(time)) ? time : "23:59";
    const d = new Date(`${date}T${t.length === 4 ? "0" + t : t}:00`);
    return isNaN(d.getTime()) ? null : d;
  } catch { return null; }
}

// Zwraca obiekt opisujący punktualność dotarcia
//   { onTime, minutes (>0 = spóźnienie), text, status: "ok"|"late" }  lub null gdy brak danych
function calcTripPunctuality(plannedDate, plannedTime, actualIso) {
  if (!plannedDate || !actualIso) return null;
  const planned = parsePlannedDateTime(plannedDate, plannedTime);
  const actual = new Date(actualIso);
  if (!planned || isNaN(actual.getTime())) return null;
  const diffMin = Math.round((actual - planned) / 60000);
  if (diffMin <= TRIP_TOLERANCE_MIN) {
    const early = diffMin < 0 ? ` (${Math.abs(diffMin)} min przed)` : diffMin === 0 ? "" : ` (+${diffMin} min)`;
    return { onTime: true, minutes: diffMin, text: `Na czas${early}`, status: "ok" };
  }
  const h = Math.floor(diffMin / 60);
  const m = diffMin % 60;
  return {
    onTime: false,
    minutes: diffMin,
    text: h > 0 ? `Spóźnienie ${h}h ${m}min` : `Spóźnienie ${m} min`,
    status: "late",
  };
}

// Oblicza średnie spalanie pojazdu w okresie (metoda "brimming" między pełnymi tankowaniami)
//   vehicleId, startDate ISO, endDate ISO, fuelEntries[] — zwraca { avgL100km, liters, km, tankings } lub null
function computeFuelConsumption(vehicleId, startDate, endDate, fuelEntries) {
  if (!vehicleId || !Array.isArray(fuelEntries) || fuelEntries.length < 2) return null;
  try {
    const windowStart = new Date(startDate);
    const windowEnd = new Date(endDate);
    if (isNaN(windowStart.getTime()) || isNaN(windowEnd.getTime())) return null;
    // rozszerz okno ±3 dni
    windowStart.setDate(windowStart.getDate() - 3);
    windowEnd.setDate(windowEnd.getDate() + 3);

    const entries = fuelEntries
      .filter(e => e.vehicleId === vehicleId && e.fullTank && !e.isAdblue && e.mileage && e.liters && e.date)
      .map(e => ({ ...e, _d: new Date(e.date), _mil: Number(e.mileage), _l: Number(e.liters) }))
      .filter(e => !isNaN(e._d.getTime()) && e._mil > 0 && e._l > 0)
      .filter(e => e._d >= windowStart && e._d <= windowEnd)
      .sort((a, b) => a._mil - b._mil);

    if (entries.length < 2) return null;
    const first = entries[0];
    const last = entries[entries.length - 1];
    const km = last._mil - first._mil;
    if (km <= 0) return null;
    // Litry: suma wszystkich tankowań od indeksu 1 (bo pierwsze = stan referencyjny)
    const liters = entries.slice(1).reduce((s, e) => s + e._l, 0);
    const avg = (liters / km) * 100;
    if (!isFinite(avg) || avg <= 0) return null;
    return {
      avgL100km: Number(avg.toFixed(2)),
      liters: Number(liters.toFixed(1)),
      km,
      tankings: entries.length,
    };
  } catch {
    return null;
  }
}

// Klasyfikuje spalanie wg progów pojazdu
//   vehicle.spalanieNorma, vehicle.spalanieAlarm → "ok" | "warn" | "alarm"
function classifyFuel(avgL100km, vehicle) {
  if (avgL100km == null) return null;
  const norma = Number(vehicle?.spalanieNorma) || SPALANIE_DEFAULT_NORMA;
  const alarm = Number(vehicle?.spalanieAlarm) || SPALANIE_DEFAULT_ALARM;
  if (avgL100km <= norma) return "ok";
  if (avgL100km <= alarm) return "warn";
  return "alarm";
}

// GŁÓWNA funkcja — buduje pełne podsumowanie trasy
//   fracht — pełny dokument frachtu (z dataZaladunku, godzZaladunku, kmStart, kmEnd, kmWszystkie...)
//   vehicle — dokument pojazdu (z spalanieNorma, spalanieAlarm)
//   driverEvents — wszystkie driverEvents (będą filtrowane po frachtId)
//   fuelEntries — wszystkie fuelEntries (filtrowane po vehicleId + okres)
function computeTripStats(fracht, vehicle, driverEvents = [], fuelEntries = []) {
  if (!fracht) return null;
  const f = fracht;
  const evs = driverEvents.filter(ev => ev.frachtId === f.id).sort((a, b) => (a.ts || "").localeCompare(b.ts || ""));
  const latestOf = (type) => evs.filter(e => e.type === type).pop();
  const undoOf = (type) => evs.filter(e => e.type === `cofnij_${type}`).pop();
  const effective = (type) => {
    const ev = latestOf(type);
    const un = undoOf(type);
    if (!ev) return null;
    if (un && un.ts > ev.ts) return null;
    return ev;
  };

  const dotarcieZal = effective("dotarcie_zaladunek");
  const startRoz = effective("start_rozladunek");       // kierowca ruszył z załadunku
  const dotarcieRoz = effective("dotarcie_rozladunek"); // dotarł na rozładunek
  // Legacy/admin eventy (mogą istnieć w starych danych lub być ustawione ręcznie)
  const zaladowano = effective("zaladowano");
  const rozladowano = effective("rozladowano");

  // Punktualnosc liczymy TYLKO z eventow `dotarcie_*` (realny moment dotarcia,
  // klikniety przez kierowce w terenie albo recznie wpisany przez admina/dyspozytora).
  // Legacy eventy `zaladowano`/`rozladowano` maja `ts` = moment rejestracji statusu w panelu,
  // co dla retroaktywnych oznaczen nie odpowiada rzeczywistemu dotarciu → fałszywe spóźnienia.
  const zalTs = dotarcieZal?.value || dotarcieZal?.ts || null;
  const rozTs = dotarcieRoz?.value || dotarcieRoz?.ts || null;

  // Punktualność — liczona z dotarć (kierowca klika "dotarłem")
  const punktZal = calcTripPunctuality(f.dataZaladunku, f.godzZaladunku, zalTs);
  const punktRoz = calcTripPunctuality(f.dataRozladunku, f.godzRozladunku, rozTs);

  // Czas trasy: od momentu gdy kierowca ruszył z załadunku (start_rozladunek)
  // do momentu dotarcia na rozładunek (dotarcie_rozladunek) — czysty czas jazdy
  // Fallback: jeśli brak start_rozladunek, użyj dotarcie_zaladunek (z załadunkiem)
  let czasTrasyMin = null;
  const tStart = startRoz?.value || startRoz?.ts || zaladowano?.value || zaladowano?.ts || zalTs;
  const tEnd = dotarcieRoz?.value || dotarcieRoz?.ts || rozladowano?.value || rozladowano?.ts || rozTs;
  if (tStart && tEnd) {
    const diff = Math.round((new Date(tEnd) - new Date(tStart)) / 60000);
    if (diff > 0) czasTrasyMin = diff;
  }

  // Czas planowany: z dataZaladunku+godzZaladunku do dataRozladunku+godzRozladunku
  let czasPlanowanyMin = null;
  const planStart = parsePlannedDateTime(f.dataZaladunku, f.godzZaladunku);
  const planEnd = parsePlannedDateTime(f.dataRozladunku, f.godzRozladunku);
  if (planStart && planEnd) {
    const diff = Math.round((planEnd - planStart) / 60000);
    if (diff > 0) czasPlanowanyMin = diff;
  }

  // Kilometry
  const kmStart = Number(f.kmStart);
  const kmEnd = Number(f.kmEnd);
  const kmRzeczywiste = (isFinite(kmStart) && isFinite(kmEnd) && kmEnd > kmStart) ? (kmEnd - kmStart) : null;
  const kmPlanowane = Number(f.kmWszystkie) || null;

  // Średnia prędkość (km/h) — tylko gdy mamy oba (km i czas)
  let sredniaPredkosc = null;
  if (kmRzeczywiste && czasTrasyMin) {
    sredniaPredkosc = Math.round((kmRzeczywiste / (czasTrasyMin / 60)) * 10) / 10;
  }

  // Spalanie — w okresie trasy
  let spalanie = null;
  if (vehicle?.id && f.dataZaladunku && (f.dataRozladunku || tEnd)) {
    const endDateISO = f.dataRozladunku || new Date(tEnd).toISOString().slice(0, 10);
    const fc = computeFuelConsumption(vehicle.id, f.dataZaladunku, endDateISO, fuelEntries);
    if (fc) {
      spalanie = { ...fc, status: classifyFuel(fc.avgL100km, vehicle) };
    }
  }

  // Ocena ogólna — najgorszy ze statusów
  const statuses = [
    punktZal?.status === "late" ? "late" : null,
    punktRoz?.status === "late" ? "late" : null,
    spalanie?.status === "alarm" ? "alarm" : spalanie?.status === "warn" ? "warn" : null,
  ].filter(Boolean);
  let ocenaOgolna = "ok";
  if (statuses.includes("alarm") || statuses.filter(s => s === "late").length >= 1) ocenaOgolna = "alarm";
  else if (statuses.includes("warn")) ocenaOgolna = "warn";

  return {
    punktZal, punktRoz,
    czasTrasyMin, czasPlanowanyMin,
    kmRzeczywiste, kmPlanowane,
    sredniaPredkosc,
    spalanie,
    ocenaOgolna,
    // raw events do debugowania/diff
    _zalTs: zalTs, _rozTs: rozTs,
  };
}

// Atlas API dateTime helper: obiekt {year,month,day,hour,minute,seconds} lub unix → ms
function atlasDateTimeToMs(dt) {
  if (dt == null) return null;
  if (typeof dt === "object" && dt.year) {
    return new Date(
      dt.year, (dt.month || 1) - 1, dt.day || 1,
      dt.hour || 0, dt.minute || 0, dt.seconds || 0
    ).getTime();
  }
  if (typeof dt === "number") return dt < 10_000_000_000 ? dt * 1000 : dt;
  const d = new Date(dt);
  return isNaN(d.getTime()) ? null : d.getTime();
}

// Formatter: minuty → "Xh Ymin" lub "Ymin"
function fmtTripDuration(min) {
  if (min == null || !isFinite(min)) return "—";
  const h = Math.floor(min / 60);
  const m = min % 60;
  if (h === 0) return `${m} min`;
  if (m === 0) return `${h} h`;
  return `${h} h ${m} min`;
}

// ─── TRIP SUMMARY PANEL — prezentacja metryk trasy ─────────────────────────────
function TripTile({ label, value, sub, status }) {
  const palette = {
    ok:    { bg: "#f0fdf4", border: "#bbf7d0", label: "#15803d", value: "#166534" },
    warn:  { bg: "#fffbeb", border: "#fde68a", label: "#92400e", value: "#78350f" },
    alarm: { bg: "#fef2f2", border: "#fecaca", label: "#b91c1c", value: "#991b1b" },
    neutral: { bg: "#f8fafc", border: "#e5e7eb", label: "#6b7280", value: "#111827" },
  }[status || "neutral"];
  return (
    <div style={{
      padding: 12, borderRadius: 12, background: palette.bg,
      border: `1px solid ${palette.border}`, minHeight: 74,
    }}>
      <div style={{ fontSize: 10, fontWeight: 700, color: palette.label, textTransform: "uppercase", letterSpacing: 0.5, marginBottom: 4 }}>{label}</div>
      <div style={{ fontSize: 16, fontWeight: 700, color: palette.value, lineHeight: 1.2 }}>{value}</div>
      {sub && <div style={{ fontSize: 11, color: "#6b7280", marginTop: 2 }}>{sub}</div>}
    </div>
  );
}

function TripSummaryPanel({ fracht, vehicle, driverEvents = [], fuelEntries = [], variant = "full" }) {
  const stats = computeTripStats(fracht, vehicle, driverEvents, fuelEntries);
  if (!stats) return null;

  const { punktZal, punktRoz, czasTrasyMin, czasPlanowanyMin, kmRzeczywiste, kmPlanowane, sredniaPredkosc, spalanie, ocenaOgolna } = stats;

  // Czy jest sens w ogóle renderować — wymagamy przynajmniej jednej metryki
  const hasAny = punktZal || punktRoz || czasTrasyMin || kmRzeczywiste || spalanie;
  if (!hasAny) return null;

  // Nagłówek z oceną ogólną
  const ocenaPalette = {
    ok:    { bg: "#f0fdf4", border: "#bbf7d0", color: "#15803d", icon: "✅", text: "Trasa zakończona OK" },
    warn:  { bg: "#fffbeb", border: "#fde68a", color: "#92400e", icon: "⚠️", text: "Trasa z zastrzeżeniami" },
    alarm: { bg: "#fef2f2", border: "#fecaca", color: "#b91c1c", icon: "🚨", text: "Trasa — przekroczenia" },
  }[ocenaOgolna];

  const isCompact = variant === "compact";
  const isDriver = variant === "driver";
  const showSpalanie = !isDriver;  // Kierowca nie widzi spalania (ograniczony panel)

  const punktZalStatus = punktZal?.status || null;
  const punktRozStatus = punktRoz?.status || null;

  // Czas planowany — różnica względem rzeczywistego (tylko info)
  const czasDiffMin = (czasTrasyMin != null && czasPlanowanyMin != null) ? czasTrasyMin - czasPlanowanyMin : null;
  const czasDiffText = czasDiffMin == null ? null :
    czasDiffMin > 0 ? `+${fmtTripDuration(czasDiffMin)} vs plan` :
    czasDiffMin < 0 ? `-${fmtTripDuration(Math.abs(czasDiffMin))} vs plan` :
    "dokładnie wg planu";

  // Km — różnica od planu
  const kmDiff = (kmRzeczywiste != null && kmPlanowane != null) ? kmRzeczywiste - kmPlanowane : null;
  const kmDiffText = kmDiff == null ? null :
    Math.abs(kmDiff) < 5 ? "≈ plan" :
    kmDiff > 0 ? `+${kmDiff} km vs plan` : `${kmDiff} km vs plan`;

  return (
    <div style={{
      background: "#fff", borderRadius: 16,
      border: `1px solid ${ocenaPalette.border}`,
      padding: isCompact ? 12 : 16,
      marginTop: isCompact ? 8 : 16,
      marginBottom: isCompact ? 8 : 16,
    }}>
      {/* Nagłówek z oceną */}
      <div style={{
        display: "flex", alignItems: "center", justifyContent: "space-between",
        padding: "8px 12px", borderRadius: 10,
        background: ocenaPalette.bg, border: `1px solid ${ocenaPalette.border}`,
        marginBottom: 12,
      }}>
        <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
          <span style={{ fontSize: 18 }}>{ocenaPalette.icon}</span>
          <div>
            <div style={{ fontSize: 12, fontWeight: 700, color: ocenaPalette.color, textTransform: "uppercase", letterSpacing: 0.5 }}>Podsumowanie trasy</div>
            <div style={{ fontSize: 13, color: ocenaPalette.color, fontWeight: 600 }}>{ocenaPalette.text}</div>
          </div>
        </div>
      </div>

      {/* Metryki — siatka */}
      <div style={{
        display: "grid",
        gridTemplateColumns: isCompact ? "repeat(2, 1fr)" : "repeat(auto-fit, minmax(140px, 1fr))",
        gap: 8,
      }}>
        {/* Punktualność załadunku */}
        {punktZal && (
          <TripTile
            label="Załadunek"
            value={punktZal.onTime ? "Na czas" : `+${punktZal.minutes} min`}
            sub={punktZal.onTime ? "w tolerancji 15 min" : "spóźnienie"}
            status={punktZalStatus === "late" ? "alarm" : "ok"}
          />
        )}
        {/* Punktualność rozładunku */}
        {punktRoz && (
          <TripTile
            label="Rozładunek"
            value={punktRoz.onTime ? "Na czas" : `+${punktRoz.minutes} min`}
            sub={punktRoz.onTime ? "w tolerancji 15 min" : "spóźnienie"}
            status={punktRozStatus === "late" ? "alarm" : "ok"}
          />
        )}
        {/* Czas trasy */}
        {czasTrasyMin != null && (
          <TripTile
            label="Czas trasy"
            value={fmtTripDuration(czasTrasyMin)}
            sub={czasDiffText || (czasPlanowanyMin ? `plan: ${fmtTripDuration(czasPlanowanyMin)}` : null)}
            status="neutral"
          />
        )}
        {/* Km rzeczywiste */}
        {kmRzeczywiste != null && (
          <TripTile
            label="Kilometry"
            value={`${kmRzeczywiste.toLocaleString("pl-PL")} km`}
            sub={kmDiffText || (kmPlanowane ? `plan: ${kmPlanowane} km` : null)}
            status="neutral"
          />
        )}
        {/* Średnia prędkość */}
        {sredniaPredkosc != null && (
          <TripTile
            label="Średnia prędkość"
            value={`${sredniaPredkosc} km/h`}
            sub={null}
            status="neutral"
          />
        )}
        {/* Spalanie (ukryte dla kierowcy) */}
        {showSpalanie && spalanie && (
          <TripTile
            label="Spalanie"
            value={`${spalanie.avgL100km} l/100km`}
            sub={
              spalanie.status === "ok"    ? "w normie" :
              spalanie.status === "warn"  ? "powyżej normy" :
              spalanie.status === "alarm" ? "przekroczenie alarmu" : null
            }
            status={spalanie.status || "neutral"}
          />
        )}
      </div>

      {/* Dodatkowe info w wersji pełnej */}
      {!isCompact && !isDriver && spalanie && (
        <div style={{ marginTop: 10, fontSize: 11, color: "#9ca3af" }}>
          Spalanie wyliczone z {spalanie.tankings} pełnych tankowań pojazdu w okresie trasy (±3 dni).
          Porównanie: norma {Number(vehicle?.spalanieNorma) || SPALANIE_DEFAULT_NORMA} / alarm {Number(vehicle?.spalanieAlarm) || SPALANIE_DEFAULT_ALARM} l/100km.
        </div>
      )}
      {!isCompact && kmRzeczywiste == null && (
        <div style={{ marginTop: 10, fontSize: 11, color: "#9ca3af" }}>
          Km rzeczywiste: brak odczytu z CAN. Sprawdź konfigurację Atlas API dla tego pojazdu.
        </div>
      )}
    </div>
  );
}

// ═══════════════════════════════════════════════════════════════════════════════
// CZAS PRACY KIEROWCY — przepisy 561/2006 + Pakiet Mobilności
// ═══════════════════════════════════════════════════════════════════════════════

// Wszystkie limity w minutach
const REGULATION = {
  DAILY_DRIVE_REGULAR: 9 * 60,       // 9h dzienny regularny
  DAILY_DRIVE_EXTENDED: 10 * 60,     // 10h — max 2× w tygodniu
  EXTENDED_PER_WEEK: 2,
  CONTINUOUS_DRIVE: 4.5 * 60,        // 4h 30min bez przerwy → przerwa 45min
  BREAK_MIN: 45,                     // minimalna przerwa 45min
  BREAK_SPLIT_FIRST: 15,             // pierwsza część podzielonej
  BREAK_SPLIT_SECOND: 30,            // druga część
  WEEKLY_DRIVE: 56 * 60,             // 56h tygodniowo
  BIWEEKLY_DRIVE: 90 * 60,           // 90h w 2 kolejnych tygodniach
  DAILY_REST_REGULAR: 11 * 60,       // 11h regularny odpoczynek
  DAILY_REST_REDUCED: 9 * 60,        // 9h skrócony
  DAILY_REST_REDUCED_PER_WEEK: 3,    // max 3× między tygodniowymi
  DAILY_REST_SPLIT_FIRST: 3 * 60,    // 3h + 9h = podzielony
  DAILY_REST_SPLIT_SECOND: 9 * 60,
  WEEKLY_REST_REGULAR: 45 * 60,      // 45h regularny tygodniowy
  WEEKLY_REST_REDUCED: 24 * 60,      // 24h skrócony tygodniowy
  WEEKLY_REST_REDUCED_PER_2WEEKS: 2, // max 2× w 2 kolejne tygodnie
  MIN_WEEKLY_REST: 35 * 60,          // min 35h w każdym tygodniu
  WORK_TIME_WEEKLY_AVG: 48 * 60,     // średnio 48h/tydz w okresie rozlicz.
  RETURN_TO_BASE_DAYS: 28,           // Pakiet Mobilności: powrót co 28 dni
};

// Typy aktywności
const ACTIVITY_TYPES = {
  drive: { label: "Jazda",          icon: "🚛", color: "#2563eb", bg: "#eff6ff" },
  work:  { label: "Inna praca",     icon: "🔧", color: "#f59e0b", bg: "#fffbeb" },
  avail: { label: "Dyspozycyjność", icon: "⏱",  color: "#64748b", bg: "#f8fafc" },
  rest:  { label: "Odpoczynek",     icon: "🛏",  color: "#22c55e", bg: "#f0fdf4" },
};

// Helper: dodaj minuty do Date
function addMin(d, min) { return new Date(d.getTime() + min * 60000); }
function minBetween(a, b) { return Math.max(0, Math.round((b - a) / 60000)); }

// Format liczby minut na "Xh Ymin" / "Ymin"
function fmtMin(m) {
  if (m == null || !isFinite(m)) return "—";
  if (m < 0) m = 0;
  const h = Math.floor(m / 60);
  const mm = Math.round(m % 60);
  if (h === 0) return `${mm} min`;
  if (mm === 0) return `${h}h`;
  return `${h}h ${mm}min`;
}

// Format zgodny z mockupem — "0h 43min"
function fmtHM(m) {
  if (m == null || !isFinite(m)) return "—";
  if (m < 0) m = 0;
  const h = Math.floor(m / 60);
  const mm = Math.round(m % 60);
  return `${h}h ${String(mm).padStart(2, "0")}min`;
}

// Konwertuj segment do obiektu z liczonymi polami
function normalizeSegment(s, now) {
  const startTs = s.startTs || s.start;
  const endTs = s.endTs || s.end || (now ? now.toISOString() : null);
  const startMs = new Date(startTs).getTime();
  const endMs = new Date(endTs).getTime();
  return {
    ...s,
    startMs,
    endMs,
    durMin: Math.max(0, Math.round((endMs - startMs) / 60000)),
    type: s.type || "avail",
    isOpen: !s.endTs && !s.end,
  };
}

// Oblicz sumy aktywności w danym zakresie
function sumByType(segments, fromMs, toMs) {
  const sums = { drive: 0, work: 0, avail: 0, rest: 0 };
  for (const s of segments) {
    const sMs = Math.max(s.startMs, fromMs);
    const eMs = Math.min(s.endMs, toMs);
    if (eMs <= sMs) continue;
    const min = Math.round((eMs - sMs) / 60000);
    sums[s.type] = (sums[s.type] || 0) + min;
  }
  return sums;
}

// Czas od ostatniej przerwy (min 45min odpoczynku lub 30min ciągłego rest/avail)
// Zwraca: minuty ciągłej jazdy od momentu ostatniej przerwy
function continuousDriveSince(segments, now) {
  const nowMs = now.getTime();
  // Szukaj ostatniej przerwy — segment typu "rest" trwający >= 45 min
  // (upraszczenie MVP: rest trwający >=45min traktujemy jako "reset" licznika 4.5h)
  let cutoffMs = 0;
  for (let i = segments.length - 1; i >= 0; i--) {
    const s = segments[i];
    if (s.type === "rest" && s.durMin >= 45 && s.endMs <= nowMs) {
      cutoffMs = s.endMs;
      break;
    }
  }
  // Sumuj tylko "drive" po cutoffMs
  let total = 0;
  for (const s of segments) {
    if (s.type !== "drive") continue;
    const sMs = Math.max(s.startMs, cutoffMs);
    const eMs = Math.min(s.endMs, nowMs);
    if (eMs > sMs) total += Math.round((eMs - sMs) / 60000);
  }
  return total;
}

// Granica "doby kierowcy" — 24h cofa się od punktu obecnego lub od ostatniego 11h+ odpoczynku
function lastDailyRestEnd(segments, now) {
  const nowMs = now.getTime();
  for (let i = segments.length - 1; i >= 0; i--) {
    const s = segments[i];
    if (s.type === "rest" && s.durMin >= REGULATION.DAILY_REST_REDUCED && s.endMs <= nowMs) {
      return s.endMs;
    }
  }
  // fallback: cofnij 24h
  return nowMs - 24 * 3600000;
}

// Granica "tygodnia" — od ostatniego 24h+ odpoczynku lub poniedziałek
function lastWeeklyRestEnd(segments, now) {
  const nowMs = now.getTime();
  for (let i = segments.length - 1; i >= 0; i--) {
    const s = segments[i];
    if (s.type === "rest" && s.durMin >= REGULATION.WEEKLY_REST_REDUCED && s.endMs <= nowMs) {
      return s.endMs;
    }
  }
  // fallback: ostatni poniedziałek 00:00
  const d = new Date(nowMs);
  const day = d.getDay(); // 0=nd, 1=pn
  const diffToMonday = day === 0 ? 6 : day - 1;
  d.setHours(0, 0, 0, 0);
  d.setDate(d.getDate() - diffToMonday);
  return d.getTime();
}

// ── Priorytet źródeł: DDD > manual > auto_gps ──
// Gdy dla kierowcy są segmenty z DDD w danym zakresie czasu, filtrujemy
// pozostałe źródła z tego zakresu (traktujemy je jako zastąpione).
function preferDddSegments(segments) {
  const dddSegs = segments.filter(s => s.source === "ddd");
  if (dddSegs.length === 0) return segments;

  // Zbuduj listę przedziałów pokrytych przez DDD
  const covered = dddSegs.map(s => [s.startMs, s.endMs]).sort((a, b) => a[0] - b[0]);
  const isCovered = (ms) => {
    for (const [a, b] of covered) {
      if (ms >= a && ms < b) return true;
    }
    return false;
  };

  // Segmenty DDD zachowujemy + te nie-DDD które leżą poza zakresem DDD
  return segments.filter(s => {
    if (s.source === "ddd") return true;
    const midMs = (s.startMs + s.endMs) / 2;
    return !isCovered(midMs);
  });
}

// ── GŁÓWNA FUNKCJA: compliance dla kierowcy ──
// segments: tablica surowych segmentów {startTs, endTs, type, ...}
// periodStart: ISO date stringu startu 28-dniowego okresu
// now: Date (aktualny moment)
// Zwraca obiekt z limitami + planem do przodu
function computeDriverCompliance(rawSegments = [], periodStart = null, now = new Date()) {
  const allSegments = rawSegments
    .map(s => normalizeSegment(s, now))
    .sort((a, b) => a.startMs - b.startMs);
  // Priorytet DDD — odfiltrowujemy GPS/manual tam gdzie mamy tachograf
  const segments = preferDddSegments(allSegments);

  const nowMs = now.getTime();
  const current = segments[segments.length - 1] || null;

  // Zakres "doby kierowcy" — od ostatniego odpoczynku dziennego
  const dayStart = lastDailyRestEnd(segments, now);
  const daySums = sumByType(segments, dayStart, nowMs);

  // Zakres tygodniowy — od ostatniego odpoczynku tygodniowego
  const weekStart = lastWeeklyRestEnd(segments, now);
  const weekSums = sumByType(segments, weekStart, nowMs);

  // Dwutygodniowy — 14 dni w tył
  const biweekStart = nowMs - 14 * 24 * 3600000;
  const biweekSums = sumByType(segments, biweekStart, nowMs);

  // Jazda ciągła od ostatniej przerwy
  const continuousDrive = continuousDriveSince(segments, now);

  // 28-dniowy okres od periodStart
  const period28 = (() => {
    if (!periodStart) return null;
    const startMs = new Date(periodStart).getTime();
    if (!isFinite(startMs)) return null;
    const deadlineMs = startMs + REGULATION.RETURN_TO_BASE_DAYS * 24 * 3600000;
    const daysPassed = Math.floor((nowMs - startMs) / (24 * 3600000));
    const daysLeft = Math.max(0, REGULATION.RETURN_TO_BASE_DAYS - daysPassed);
    return { startMs, deadlineMs, daysPassed, daysLeft };
  })();

  // Liczba użytych 10h dni w bieżącym tygodniu (jazda >= 9h 01min)
  let extendedDaysUsed = 0;
  {
    const dayMs = 24 * 3600000;
    for (let t = weekStart; t < nowMs; t += dayMs) {
      const dSums = sumByType(segments, t, Math.min(t + dayMs, nowMs));
      if (dSums.drive > 9 * 60) extendedDaysUsed++;
    }
  }

  // Czas pracy w tym tygodniu (drive + work) dla średniej 48h
  const weekWorkTime = weekSums.drive + weekSums.work;

  // Stan aktualny
  const currentStateType = current?.isOpen ? current.type : null;

  // Statystyki źródeł danych
  const sourceStats = allSegments.reduce((acc, s) => {
    acc[s.source || "unknown"] = (acc[s.source || "unknown"] || 0) + 1;
    return acc;
  }, {});
  const hasDdd = (sourceStats.ddd || 0) > 0;

  return {
    now: nowMs,
    segments,
    current,
    currentStateType,
    continuousDrive,
    daily: {
      drive: daySums.drive,
      work: daySums.work,
      avail: daySums.avail,
      rest: daySums.rest,
      limit: REGULATION.DAILY_DRIVE_REGULAR,
      limitExtended: REGULATION.DAILY_DRIVE_EXTENDED,
      extendedDaysUsed,
      extendedDaysAllowed: REGULATION.EXTENDED_PER_WEEK,
      start: dayStart,
    },
    weekly: {
      drive: weekSums.drive,
      work: weekSums.work,
      workTime: weekWorkTime,
      limit: REGULATION.WEEKLY_DRIVE,
      limitWorkTime: REGULATION.WORK_TIME_WEEKLY_AVG,
      start: weekStart,
    },
    biweekly: {
      drive: biweekSums.drive,
      limit: REGULATION.BIWEEKLY_DRIVE,
      start: biweekStart,
    },
    period28,
    sources: sourceStats,
    hasDdd,
  };
}

// ── PLAN DO PRZODU — co i kiedy powinno się wydarzyć ──
function computeDriverPlan(compliance, now = new Date()) {
  if (!compliance) return null;
  const nowMs = now.getTime();

  // 1. Następna obligatoryjna przerwa 45 min — gdy jazda ciągła osiągnie 4h 30min
  const driveToBreak = Math.max(0, REGULATION.CONTINUOUS_DRIVE - compliance.continuousDrive);
  const nextBreakMs = nowMs + driveToBreak * 60000;
  const breakEndMs = nextBreakMs + REGULATION.BREAK_MIN * 60000;

  // 2. Koniec jazdy dziennej — gdy osiągniemy limit 9h (lub 10h jeśli dozwolone)
  const canExtend = compliance.daily.extendedDaysUsed < compliance.daily.extendedDaysAllowed;
  const dailyLimit = canExtend ? compliance.daily.limitExtended : compliance.daily.limit;
  const driveToDailyEnd = Math.max(0, dailyLimit - compliance.daily.drive);
  // Uwzględnij pośrednią przerwę (jeśli jazda > 4.5h, dodaj 45min)
  const willNeedBreak = driveToDailyEnd > driveToBreak;
  const endOfDayMs = nowMs + driveToDailyEnd * 60000 + (willNeedBreak ? REGULATION.BREAK_MIN * 60000 : 0);

  // 3. Odpoczynek dzienny 11h (lub 9h jeśli skrócony)
  const dailyRestEndMs = endOfDayMs + REGULATION.DAILY_REST_REGULAR * 60000;

  // 4. Odpoczynek tygodniowy — ile godzin zostało do końca bieżącego tygodnia (regularny)
  //    Prosty model: aktualny tydzień kończy się 6 dni od weekStart, o 00:00 dnia 7.
  const weekStartDate = new Date(compliance.weekly.start);
  const weekEndDate = new Date(weekStartDate);
  weekEndDate.setDate(weekStartDate.getDate() + 6);
  weekEndDate.setHours(0, 0, 0, 0);
  const weeklyRestStartMs = weekEndDate.getTime();
  const weeklyRestEndMs = weeklyRestStartMs + REGULATION.WEEKLY_REST_REGULAR * 60000;

  // 5. Powrót do bazy
  const returnToBase = compliance.period28 ? {
    deadlineMs: compliance.period28.deadlineMs,
    daysLeft: compliance.period28.daysLeft,
  } : null;

  return {
    nextBreak: {
      driveMinToGo: driveToBreak,
      atMs: nextBreakMs,
      endMs: breakEndMs,
      durationMin: REGULATION.BREAK_MIN,
    },
    endOfDay: {
      driveMinToGo: driveToDailyEnd,
      atMs: endOfDayMs,
      extendedAllowed: canExtend,
      dailyLimit,
    },
    dailyRest: {
      startMs: endOfDayMs,
      endMs: dailyRestEndMs,
      durationMin: REGULATION.DAILY_REST_REGULAR,
    },
    weeklyRest: {
      startMs: weeklyRestStartMs,
      endMs: weeklyRestEndMs,
      durationMin: REGULATION.WEEKLY_REST_REGULAR,
    },
    returnToBase,
  };
}

// Format timestamp → "HH:MM" lub "dd.MM HH:MM"
function fmtTimeShort(ms) {
  if (!ms) return "—";
  const d = new Date(ms);
  const today = new Date();
  const isToday = d.toDateString() === today.toDateString();
  const tomorrow = new Date(today); tomorrow.setDate(tomorrow.getDate() + 1);
  const isTomorrow = d.toDateString() === tomorrow.toDateString();
  const hm = `${String(d.getHours()).padStart(2, "0")}:${String(d.getMinutes()).padStart(2, "0")}`;
  if (isToday) return hm;
  if (isTomorrow) return `jutro ${hm}`;
  return `${String(d.getDate()).padStart(2, "0")}.${String(d.getMonth() + 1).padStart(2, "0")} ${hm}`;
}

